+    PackedRgba::rgb(100, 255, 200), // clawdbot — mint
+    PackedRgba::rgb(255, 220, 150), // vibe — peach
+    PackedRgba::rgb(150, 150, 255), // openclaw — periwinkle
+];
+
+fn agent_color(idx: usize) -> PackedRgba {
+    AGENT_COLORS[idx % AGENT_COLORS.len()]
